import { Effect } from 'effect'
import { describe, expect, it } from 'vitest'
import { parse } from '../src/parser/parser.js'

describe('markdown parser', () => {
  describe('basic parsing', () => {
    it('parses a simple markdown document', async () => {
      const content = `# Hello World

This is a paragraph.

## Section One

Content for section one.

## Section Two

Content for section two.
`

      const result = await Effect.runPromise(parse(content))

      expect(result.title).toBe('Hello World')
      expect(result.sections).toHaveLength(1) // One H1 as root
      expect(result.sections[0]?.heading).toBe('Hello World')
      expect(result.sections[0]?.children).toHaveLength(2) // Two H2 children
    })

    it('extracts frontmatter', async () => {
      const content = `---
title: Custom Title
author: Test Author
tags:
  - markdown
  - parser
---

# Heading

Content here.
`

      const result = await Effect.runPromise(parse(content))

      expect(result.frontmatter).toEqual({
        title: 'Custom Title',
        author: 'Test Author',
        tags: ['markdown', 'parser'],
      })
      expect(result.title).toBe('Heading') // H1 takes precedence
    })

    it('uses frontmatter title when no H1 present', async () => {
      const content = `---
title: Frontmatter Title
---

## Only an H2

Some content.
`

      const result = await Effect.runPromise(parse(content))

      expect(result.title).toBe('Frontmatter Title')
    })
  })

  describe('section hierarchy', () => {
    it('builds proper section hierarchy', async () => {
      const content = `# Root

## Level 2 A

### Level 3 A1

Content

### Level 3 A2

Content

## Level 2 B

Content
`

      const result = await Effect.runPromise(parse(content))

      expect(result.sections).toHaveLength(1)

      const root = result.sections[0]!
      expect(root.heading).toBe('Root')
      expect(root.children).toHaveLength(2)

      const level2A = root.children[0]!
      expect(level2A.heading).toBe('Level 2 A')
      expect(level2A.children).toHaveLength(2)

      const level3A1 = level2A.children[0]!
      expect(level3A1.heading).toBe('Level 3 A1')
      expect(level3A1.children).toHaveLength(0)
    })
  })

  describe('links', () => {
    it('extracts internal links', async () => {
      const content = `# Links

Check out [other doc](./other.md).

And [section link](#section).
`

      const result = await Effect.runPromise(parse(content))

      expect(result.links).toHaveLength(2)
      expect(result.links[0]?.type).toBe('internal')
      expect(result.links[0]?.href).toBe('./other.md')
      expect(result.links[1]?.type).toBe('internal')
      expect(result.links[1]?.href).toBe('#section')
    })

    it('extracts external links', async () => {
      const content = `# External Links

Visit [Google](https://google.com).
`

      const result = await Effect.runPromise(parse(content))

      expect(result.links).toHaveLength(1)
      expect(result.links[0]?.type).toBe('external')
      expect(result.links[0]?.href).toBe('https://google.com')
    })

    it('extracts image links', async () => {
      const content = `# Images

![Alt text](./image.png)
`

      const result = await Effect.runPromise(parse(content))

      expect(result.links).toHaveLength(1)
      expect(result.links[0]?.type).toBe('image')
      expect(result.links[0]?.text).toBe('Alt text')
    })
  })

  describe('code blocks', () => {
    it('extracts code blocks with language', async () => {
      const content = `# Code

\`\`\`typescript
const x = 1;
\`\`\`
`

      const result = await Effect.runPromise(parse(content))

      expect(result.codeBlocks).toHaveLength(1)
      expect(result.codeBlocks[0]?.language).toBe('typescript')
      expect(result.codeBlocks[0]?.content).toBe('const x = 1;')
    })

    it('extracts code blocks without language', async () => {
      const content = `# Code

\`\`\`
plain text
\`\`\`
`

      const result = await Effect.runPromise(parse(content))

      expect(result.codeBlocks).toHaveLength(1)
      expect(result.codeBlocks[0]?.language).toBeNull()
    })
  })

  describe('GFM features', () => {
    it('detects tables in sections', async () => {
      const content = `# Tables

| Header 1 | Header 2 |
| -------- | -------- |
| Cell 1   | Cell 2   |
`

      const result = await Effect.runPromise(parse(content))

      expect(result.sections[0]?.metadata.hasTable).toBe(true)
    })

    it('detects lists in sections', async () => {
      const content = `# Lists

- Item 1
- Item 2
- Item 3
`

      const result = await Effect.runPromise(parse(content))

      expect(result.sections[0]?.metadata.hasList).toBe(true)
    })

    it('detects task lists', async () => {
      const content = `# Tasks

- [ ] Todo item
- [x] Completed item
`

      const result = await Effect.runPromise(parse(content))

      expect(result.sections[0]?.metadata.hasList).toBe(true)
    })
  })

  describe('metadata', () => {
    it('counts tokens and words', async () => {
      const content = `# Document

This is some text content for testing token counting.
`

      const result = await Effect.runPromise(parse(content))

      expect(result.metadata.tokenCount).toBeGreaterThan(0)
      expect(result.metadata.wordCount).toBeGreaterThan(0)
    })

    it('counts links and code blocks', async () => {
      const content = `# Test

[Link 1](./a.md)
[Link 2](./b.md)

\`\`\`js
code
\`\`\`

\`\`\`py
code
\`\`\`
`

      const result = await Effect.runPromise(parse(content))

      expect(result.metadata.linkCount).toBe(2)
      expect(result.metadata.codeBlockCount).toBe(2)
    })

    it('counts headings', async () => {
      const content = `# H1

## H2

### H3

## Another H2
`

      const result = await Effect.runPromise(parse(content))

      expect(result.metadata.headingCount).toBe(4)
    })
  })
})

import { describe, expect, it } from 'vitest'
import { countTokensApprox, countWords } from '../src/utils/tokens.js'

describe('token utilities', () => {
  describe('countWords', () => {
    it('counts words in a simple sentence', () => {
      expect(countWords('Hello world')).toBe(2)
    })

    it('handles empty string', () => {
      expect(countWords('')).toBe(0)
    })

    it('handles whitespace only', () => {
      expect(countWords('   ')).toBe(0)
    })

    it('handles multiple spaces between words', () => {
      expect(countWords('hello    world')).toBe(2)
    })

    it('handles newlines and tabs', () => {
      expect(countWords('hello\nworld\there')).toBe(3)
    })
  })

  describe('countTokensApprox', () => {
    it('estimates tokens for short text', () => {
      // Approximation is ~4 chars per token
      const text = 'Hello world' // 11 chars
      const estimate = countTokensApprox(text)
      expect(estimate).toBeGreaterThan(0)
      expect(estimate).toBe(Math.ceil(11 / 4)) // Should be 3
    })

    it('handles empty string', () => {
      expect(countTokensApprox('')).toBe(0)
    })

    it('estimates longer text', () => {
      const text =
        'This is a longer piece of text that should have more tokens.'
      const estimate = countTokensApprox(text)
      expect(estimate).toBeGreaterThan(10)
    })
  })
})

/**
 * Tests for structural search
 */

import * as fs from 'node:fs/promises'
import * as path from 'node:path'
import { Effect } from 'effect'
import { afterAll, beforeAll, describe, expect, it } from 'vitest'
import { buildIndex } from '../src/index/indexer.js'
import {
  formatContextForLLM,
  getContext,
  search,
} from '../src/search/searcher.js'

// Test fixture directory
const TEST_DIR = path.join(process.cwd(), 'tests', 'fixtures', 'search')

// Helper to run Effect
const runEffect = <A, E>(effect: Effect.Effect<A, E>) =>
  Effect.runPromise(effect)

describe('search', () => {
  beforeAll(async () => {
    // Create test fixtures
    await fs.mkdir(TEST_DIR, { recursive: true })

    // Create test markdown files
    await fs.writeFile(
      path.join(TEST_DIR, 'doc1.md'),
      `# Document One

## Introduction

This is the introduction section.

## Code Example

Here's some code:

\`\`\`typescript
const x = 1;
\`\`\`

## Summary

A brief summary.
`,
    )

    await fs.writeFile(
      path.join(TEST_DIR, 'doc2.md'),
      `# Document Two

## Overview

An overview of the document.

## Data Table

| Column A | Column B |
|----------|----------|
| Value 1  | Value 2  |

## Tasks

- Task 1
- Task 2
- Task 3
`,
    )

    // Build index
    await runEffect(buildIndex(TEST_DIR, { force: true }))
  })

  afterAll(async () => {
    // Clean up
    await fs.rm(TEST_DIR, { recursive: true, force: true })
  })

  describe('search()', () => {
    it('should return all sections without filters', async () => {
      const results = await runEffect(search(TEST_DIR))
      expect(results.length).toBeGreaterThan(0)
    })

    it('should filter by heading pattern', async () => {
      const results = await runEffect(
        search(TEST_DIR, { heading: 'Introduction|Overview' }),
      )
      expect(results.length).toBe(2)
      expect(results.map((r) => r.section.heading)).toContain('Introduction')
      expect(results.map((r) => r.section.heading)).toContain('Overview')
    })

    it('should filter by path pattern', async () => {
      const results = await runEffect(
        search(TEST_DIR, { pathPattern: 'doc1*' }),
      )
      expect(results.length).toBeGreaterThan(0)
      for (const result of results) {
        expect(result.section.documentPath).toMatch(/doc1/)
      }
    })

    it('should filter by hasCode', async () => {
      const results = await runEffect(search(TEST_DIR, { hasCode: true }))
      expect(results.length).toBeGreaterThan(0)
      for (const result of results) {
        expect(result.section.hasCode).toBe(true)
      }
    })

    it('should filter by hasTable', async () => {
      const results = await runEffect(search(TEST_DIR, { hasTable: true }))
      expect(results.length).toBeGreaterThan(0)
      for (const result of results) {
        expect(result.section.hasTable).toBe(true)
      }
    })

    it('should filter by hasList', async () => {
      const results = await runEffect(search(TEST_DIR, { hasList: true }))
      expect(results.length).toBeGreaterThan(0)
      for (const result of results) {
        expect(result.section.hasList).toBe(true)
      }
    })

    it('should respect limit', async () => {
      const results = await runEffect(search(TEST_DIR, { limit: 2 }))
      expect(results.length).toBe(2)
    })
  })

  describe('getContext()', () => {
    it('should return document context', async () => {
      const context = await runEffect(
        getContext(TEST_DIR, path.join(TEST_DIR, 'doc1.md')),
      )
      expect(context.title).toBe('Document One')
      expect(context.sections.length).toBeGreaterThan(0)
    })

    it('should respect maxTokens', async () => {
      const fullContext = await runEffect(
        getContext(TEST_DIR, path.join(TEST_DIR, 'doc1.md')),
      )
      const limitedContext = await runEffect(
        getContext(TEST_DIR, path.join(TEST_DIR, 'doc1.md'), { maxTokens: 50 }),
      )
      expect(limitedContext.includedTokens).toBeLessThanOrEqual(50)
      expect(limitedContext.includedTokens).toBeLessThan(
        fullContext.totalTokens,
      )
    })
  })

  describe('formatContextForLLM()', () => {
    it('should format context as readable text', async () => {
      const context = await runEffect(
        getContext(TEST_DIR, path.join(TEST_DIR, 'doc1.md')),
      )
      const formatted = formatContextForLLM(context)
      expect(formatted).toContain('# Document One')
      expect(formatted).toContain('Path: doc1.md')
      expect(formatted).toContain('tokens')
    })

    it('should include content metadata markers', async () => {
      const context = await runEffect(
        getContext(TEST_DIR, path.join(TEST_DIR, 'doc1.md')),
      )
      const formatted = formatContextForLLM(context)
      expect(formatted).toContain('[code]')
    })
  })
})

